            aOrbiterK = (aOrbiterK ^ aOrbiterG) ^ 0x0F524BA5CF49CF53ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x233038BEBC33A9C5ULL), 29U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 0xEF962CE920D89758ULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 0x1BBCAA2C54D499C4ULL;
            aOrbiterE = RotL64((aOrbiterE * 0xE956D5074CAEAE2BULL), 35U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterB) + 0xF0EFB2790343D9CBULL;
            aOrbiterG = ((aOrbiterG ^ aOrbiterI) ^ 0x0BEA89878D08677AULL) ^ aPhaseCOrbiterUpdateSaltB[((aIndex + 11U)) & S_SALT1];
            aOrbiterG = RotL64((aOrbiterG * 0x668A8CC6DAFA4237ULL), 19U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterC) + 0x64B71636C15D32E2ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterE) ^ 0x66EC83202AD9FC18ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x7A086F848DC7CF6BULL), 47U);
            //
            aIngress = aOrbiterI ^ RotL64(aOrbiterE, 38U);
            aIngress = aIngress + (aOrbiterJ ^ RotL64(aOrbiterB, 13U));
            aIngress = aIngress + (aOrbiterK ^ RotL64(aOrbiterC, 41U));
            aIngress = aIngress + (aOrbiterG ^ RotL64(aOrbiterA, 23U));
