            aOrbiterE = (aOrbiterE + aOrbiterC) + 0x8F3147BD216D62C3ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterE) ^ 0x2F455758E149A6EDULL;
            aOrbiterH = RotL64((aOrbiterH * 0xB338C1E408769099ULL), 35U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterJ) + 0x877F20C053F2F44DULL) + aPhaseHOrbiterUpdateSaltD[((aIndex + 28U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterB) ^ 0x958F323179FBF5EEULL;
            aOrbiterK = RotL64((aOrbiterK * 0xFC5C3B2D73B26659ULL), 53U);
            //
