            aOrbiterD = RotL64((aOrbiterD * 0x90D063211043C683ULL), 29U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterA) + 0xFB9218261108E40CULL) + aPhaseHOrbiterUpdateSaltF[((aIndex + 19U)) & S_SALT1];
            aOrbiterB = ((aOrbiterB ^ aOrbiterH) ^ 0xBC4766EF5ACAEA44ULL) ^ aPhaseHOrbiterUpdateSaltE[((aIndex + 23U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 0xE76C432B2545FB29ULL), 11U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterG) + 0xB534CF17B812E766ULL;
