            //
            aOrbiterK = (aOrbiterK + aOrbiterE) + 0xC55273665B72BD62ULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 0xC83F8D9E4B89F9B6ULL;
